#include <stdio.h>
#include <stdlib.h>
#include <string.h>

// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node* next;
} Node;

// Define the structure for a tree
typedef struct Tree {
    Node* root;
} Tree;

// Function to create a new tree node
Node* createNode(int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->value = value;
    newNode->next = NULL;
    return newNode;
}

// Function to create a new tree
Tree* createTree() {
    Tree* newTree = (Tree*)malloc(sizeof(Tree));
    newTree->root = NULL;
    return newTree;
}

// Function to add an edge to the tree
void addEdge(Tree* tree, int u, int v) {
    Node* newNode = createNode(v);
    newNode->next = tree->root;
    tree->root = newNode;
}

// Function to find a triple-tree decomposition
void findDecomposition(Tree* tree) {
    // Iterate over all possible combinations of edges
    for (Node* current = tree->root; current != NULL; current = current->next) {
        for (Node* next = current->next; next != NULL; next = next->next) {
            for (Node* nextNext = next->next; nextNext != NULL; nextNext = nextNext->next) {
                // Check if the current combination is a valid decomposition
                if (current->value != next->value && current->value != nextNext->value && next->value != nextNext->value) {
                    printf("YES\n");
                    printf("%d %d %d %d\n", current->value, next->value, nextNext->value, tree->root->value);
                    return;
                }
            }
        }
    }
    printf("NO\n");
}

int main() {
    int T;
    scanf("%d", &T);
    for (int i = 0; i < T; i++) {
        int N;
        scanf("%d", &N);
        Tree* tree = createTree();
        for (int j = 0; j < N - 1; j++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(tree, u, v);
        }
        findDecomposition(tree);
    }
    return 0;
}

